import { d3_map, d3_select } from '../core/d3-constants';
import { ParserRegistry } from '../core/parser-registry';
import { roundedRect } from '../utils/zcsvgutils';
import { defined, getBorderRadius, isUndefined, simpleClone } from '../utils/zcutils';

export function _mainBar(data) {
    let KEY = this.KEY || 'bar';
    let _this = this;
    let currentData = data.data,
        builderC = this.builderC,
        anime_config = builderC.animationOptions ?? {},
        racing = this.chart.racing && this.chart.racing.syncTransition,
        morphing = this.chart.systemConf.chart.plot.morph.enabled && this.chart.oldSeriesInfo,
        liveUpdate = builderC.liveUpdate,
        attrs = {},
        renderer = this.chart.renderer[builderC.rendererIndex],
        seriesIdx = renderer.commonRendererProp().datasetIndex();

    let _styles = this.helpers.styles[KEY] ?? {};

    let enterMarks, updateMarks, exitMarks;
    /*
    Default enter marks
     */
    enterMarks = {
        d: d => _this.helpers.position[KEY].start(d)
    };

    if (racing) {
        KEY = 'bar_racing';
        enterMarks = {
            d: d => _this.helpers.position[KEY].start(d)
        };
        updateMarks = [
            {
                transition: racing,
                d: d => _this.helpers.position[KEY].end(d)
            }
        ];

        exitMarks = {
            transition: racing,
            d: d => _this.helpers.position[KEY].exit(d)
        };
    } else if (morphing) {
        updateMarks = [
            {
                duration: anime_config._duration,
                d: {
                    property: 'attrTween',
                    to: function(d, i) {
                        let interpolator = _this.helpers.position.bar_morphing.interpolator[i];
                        return function(t) {
                            return _this.helpers.position.bar_morphing.line_d3(
                                interpolator.map(function(p) {
                                    return p(t);
                                })
                            );
                        };
                    }
                }
            },
            {
                duration: 0,
                d: d => _this.helpers.position[KEY].end(d)
            }
        ];
    } else if (liveUpdate) {
        updateMarks = [
            {
                duration: _this.phase == 'redraw' ? anime_config._duration : 0,
                d: d => _this.helpers.position[KEY].end(d)
            }
        ];
        exitMarks = { 
            duration: anime_config._exitduration,
            d: d => _this.helpers.position[KEY].exit(d)
        };
    } else {
        updateMarks = [
            {
                duration: _this.phase == 'redraw' ? _this.chart.phase == 'legendFilter' ?
                    anime_config._duration - anime_config._exitduration : anime_config._duration : 0,
                delay: _this.chart.phase == 'legendFilter' ? anime_config._exitduration : anime_config._delay,
                d: d => _this.helpers.position[KEY].stop_1(d)
            },
            {
                duration: anime_config._duration,
                delay: anime_config._delay,
                easing: anime_config.easingType,
                d: (d, i) => _this.helpers.position[KEY].end(d)
            }
        ];

        exitMarks = {
            duration: anime_config._exitduration,
            d: d => _this.helpers.position[KEY].exit(d)
        };
    }

    if (this.chart.dataObject.hierarchical) {
        attrs = {
            levelbycolumn: d => d.levelByColumn,
            levelbyrow: d => d.levelByRow
        };
    }

    let _mainPath = {
        mark: 'g',
        selector: '.subseries',
        data: function() {
            return data.disabled ? [] : data.data;
        },
        properties: {
            attrs: {
                class: (d, i) => {
                    d.subseriesIdx = i;
                    return `subseries subseries_${i}`;
                }
            }
        },
        anime: {
            exit: {
                delay: anime_config._exitduration
            }
        },
        children: [
            {
                mark: '_rect',
                selector: '.zc_bar',
                data: function(d, i) {
                    return data.disabled ? [] : _this.helpers.filterData(d);
                },
                dataAccessor: _ => _this.chart.dataset.getX(_),
                config: {
                    enter: enterMarks,
                    strokeWidth: _styles.strokeWidth,
                    dashStyle: _styles.strokeDasharray,
                    lineCap: 'none'
                },
                anime: {
                    update: updateMarks,
                    exit: exitMarks
                },
                properties: {
                    attrs,
                    styles: {
                        fill: (d, i) => _styles.fill(d, i),
                        stroke: (d, i) => _styles.stroke(d, i),
                        'fill-opacity': _styles.fillOpacity,
                        opacity: _styles.opacity
                    }
                }
            }
        ]
    };
    return _mainPath;
}

ParserRegistry.marks('bar.default', _mainBar);

